**ShipmentTracker/Services/ServerShipmentService.cs**:
```csharp
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db, AuthenticationStateProvider authStateProvider) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        var authState = await authStateProvider.GetAuthenticationStateAsync();
        var user = authState.User;

        IQueryable<Shipment> query = db.Shipments;

        if (!user.IsInRole("Dispatcher"))
        {
            var email = user.Identity?.Name ?? "";
            query = query.Where(s => s.CustomerEmail == email);
        }

        return await query.Select(s => new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = Enum.Parse<ShipmentStatus>(s.Status),
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            ActualDelivery = s.ActualDelivery,
            CustomerEmail = s.CustomerEmail,
            Description = s.Description
        }).ToListAsync();
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        if (s is null) return null;
        return new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = Enum.Parse<ShipmentStatus>(s.Status),
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            ActualDelivery = s.ActualDelivery,
            CustomerEmail = s.CustomerEmail,
            Description = s.Description
        };
    }

    public async Task<bool> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return false;
        shipment.Status = status.ToString();
        if (status == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return true;
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = "SHP-" + Guid.NewGuid().ToString("N")[..8].ToUpperInvariant(),
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = dto.Status.ToString(),
            ShippedDate = dto.ShippedDate,
            EstimatedDelivery = dto.EstimatedDelivery,
            CustomerEmail = dto.CustomerEmail,
            Description = dto.Description
        };
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = Enum.Parse<ShipmentStatus>(shipment.Status),
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description
        };
    }
}
```

