using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db, AuthenticationStateProvider authStateProvider) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        var authState = await authStateProvider.GetAuthenticationStateAsync();
        var user = authState.User;

        IQueryable<Shipment> query = db.Shipments;

        if (!user.IsInRole("Dispatcher"))
        {
            var email = user.Identity?.Name ?? "";
            query = query.Where(s => s.CustomerEmail == email);
        }

        return await query.Select(s => new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = Enum.Parse<ShipmentStatus>(s.Status),
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            ActualDelivery = s.ActualDelivery,
            CustomerEmail = s.CustomerEmail,
            Description = s.Description
        }).ToListAsync();
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var s = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        if (s is null) return null;
        return new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = Enum.Parse<ShipmentStatus>(s.Status),
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            ActualDelivery = s.ActualDelivery,
            CustomerEmail = s.CustomerEmail,
            Description = s.Description
        };
    }

    public async Task<bool> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return false;
        shipment.Status = status.ToString();
        if (status == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return true;
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = "SHP-" + Guid.NewGuid().ToString("N")[..8].ToUpperInvariant(),
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = dto.Status.ToString(),
            ShippedDate = dto.ShippedDate,
            EstimatedDelivery = dto.EstimatedDelivery,
            CustomerEmail = dto.CustomerEmail,
            Description = dto.Description
        };
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = Enum.Parse<ShipmentStatus>(shipment.Status),
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description
        };
    }
}

@page "/track"
@page "/track/{TrackingNumber}"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Components.Web
@inject IShipmentService ShipmentService
@rendermode InteractiveAuto

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-XXXXXXXX)"
                   @bind="searchTrackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                @if (isSearching) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Track
            </button>
        </div>
    </div>
</div>

@if (searchPerformed && shipment is null)
{
    <div class="alert alert-warning">No shipment found with tracking number "<strong>@lastSearched</strong>".</div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Description:</strong> @shipment.Description</p>
                    <p><strong>Origin:</strong> @shipment.Origin</p>
                    <p><strong>Destination:</strong> @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                    @if (shipment.ActualDelivery.HasValue)
                    {
                        <p><strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</p>
                    }
                </div>
            </div>
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(shipment.Status))%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool isSearching;
    private bool searchPerformed;
    private string lastSearched = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrWhiteSpace(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await SearchShipment();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber)) return;
        isSearching = true;
        lastSearched = searchTrackingNumber.Trim();
        shipment = await ShipmentService.TrackShipmentAsync(lastSearched);
        searchPerformed = true;
        isSearching = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 75,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };
}

@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Web
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService
@rendermode InteractiveAuto

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" style="width:300px;" />
    </div>
    <button class="btn btn-success" @onclick="() => showCreateForm = !showCreateForm">
        @(showCreateForm ? "Cancel" : "+ New Shipment")
    </button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5>Create New Shipment</h5>
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newShipment.Description" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Customer Email</label>
                    <input type="email" class="form-control" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Shipped Date</label>
                    <input type="date" class="form-control" @bind="newShipment.ShippedDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <button class="btn btn-primary" @onclick="CreateShipment" disabled="@isCreating">
                        @if (isCreating) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Create Shipment
                    </button>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(createMessage))
            {
                <div class="alert @(createSuccess ? "alert-success" : "alert-danger") mt-3">@createMessage</div>
            }
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Description</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Customer</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Description</td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.ShippedDate.ToString("MMM dd")</td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd")</td>
                        <td>@s.CustomerEmail</td>
                        <td>
                            <select class="form-select form-select-sm" style="width:150px;"
                                    value="@s.Status" @onchange="e => UpdateStatus(s, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showCreateForm;
    private ShipmentDto newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };
    private bool isCreating;
    private string createMessage = string.Empty;
    private bool createSuccess;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var success = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (success)
            {
                shipment.Status = newStatus;
                if (newStatus == ShipmentStatus.Delivered)
                    shipment.ActualDelivery = DateTime.UtcNow;
            }
        }
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        createMessage = string.Empty;
        var result = await ShipmentService.CreateShipmentAsync(newShipment);
        if (result is not null)
        {
            shipments?.Insert(0, result);
            newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };
            createMessage = $"Shipment {result.TrackingNumber} created successfully!";
            createSuccess = true;
            showCreateForm = false;
        }
        else
        {
            createMessage = "Failed to create shipment.";
