using System.Security.Claims;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static WebApplication MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            IQueryable<Shipment> query = db.Shipments;

            if (!user.IsInRole("Dispatcher"))
            {
                var email = user.Identity?.Name ?? "";
                query = query.Where(s => s.CustomerEmail == email);
            }

            var shipments = await query.Select(s => MapToDto(s)).ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization();

        group.MapGet("/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(MapToDto(shipment));
        });

        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            shipment.Status = dto.Status.ToString();
            if (dto.Status == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = dto.Status.ToString(),
                ShippedDate = dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                CustomerEmail = dto.CustomerEmail,
                Description = dto.Description
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{shipment.TrackingNumber}", MapToDto(shipment));
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

        return app;
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = Enum.Parse<ShipmentStatus>(s.Status),
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };

    private static string GenerateTrackingNumber()
    {
        const string chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        var random = Random.Shared;
        var code = new char[8];
        for (int i = 0; i < 8; i++)
            code[i] = chars[random.Next(chars.Length)];
        return "SHP-" + new string(code);
    }
}

