@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showCreateForm;
    private ShipmentDto newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };
    private bool isCreating;
    private string createMessage = string.Empty;
    private bool createSuccess;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s => string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var success = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (success)
            {
                shipment.Status = newStatus;
                if (newStatus == ShipmentStatus.Delivered)
                    shipment.ActualDelivery = DateTime.UtcNow;
            }
        }
    }

    private async Task CreateShipment()
    {
        isCreating = true;
        createMessage = string.Empty;
        var result = await ShipmentService.CreateShipmentAsync(newShipment);
        if (result is not null)
        {
            shipments?.Insert(0, result);
            newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };
            createMessage = $"Shipment {result.TrackingNumber} created successfully!";
            createSuccess = true;
            showCreateForm = false;
        }
        else
        {
            createMessage = "Failed to create shipment.";
            createSuccess = false;
        }
        isCreating = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-warning text-dark"
    };
}

